QHeaderView::section {
    background: #F8FAFC;
    border: none;
    border-right: 1px solid #E2E8F0;
    border-bottom: 1px solid #E2E8F0;
    padding: 6px 10px;
    font-weight: 600;
    color: #475569;
    font-size: 12px;
}

/* ── Sliders ── */
QSlider::groove:horizontal {
    height: 4px;
    background: #E2E8F0;
    border-radius: 2px;
}
QSlider::handle:horizontal {
    background: #0369A1;
    border: none;
    width: 16px;
    height: 16px;
    margin: -6px 0;
    border-radius: 8px;
}
QSlider::handle:horizontal:hover {
    background: #0284C7;
}
QSlider::sub-page:horizontal {
    background: #0369A1;
    border-radius: 2px;
}

/* ── Progress Bars ── */
QProgressBar {
    background: #E2E8F0;
    border: none;
    border-radius: 4px;
    height: 6px;
    text-align: center;
    color: transparent;
}
QProgressBar::chunk {
    background: #0369A1;
    border-radius: 4px;
}

/* ── Status Bar ── */
QStatusBar {
    background: #FFFFFF;
    border-top: 1px solid #E2E8F0;
    color: #64748B;
    font-size: 12px;
}
QStatusBar::item { border: none; }

/* ── Splitter ── */
QSplitter::handle {
    background: #E2E8F0;
}
QSplitter::handle:hover {
    background: #0369A1;
}
QSplitter::handle:horizontal { width: 4px; }
QSplitter::handle:vertical   { height: 4px; }

/* ── Checkboxes and Radio Buttons ── */
QCheckBox, QRadioButton {
    color: #0F172A;
    spacing: 8px;
}
QCheckBox::indicator, QRadioButton::indicator {
    width: 16px;
    height: 16px;
    border: 1.5px solid #CBD5E1;
    border-radius: 3px;
    background: #FFFFFF;
}
QCheckBox::indicator:checked, QRadioButton::indicator:checked {
    background: #0369A1;
    border-color: #0369A1;
}
QCheckBox::indicator:hover, QRadioButton::indicator:hover {
    border-color: #0369A1;
}
QRadioButton::indicator { border-radius: 8px; }

/* ── Tooltips ── */
QToolTip {
    background: #0F172A;
    color: #F8FAFC;
    border: none;
    border-radius: 5px;
    padding: 5px 8px;
    font-size: 12px;
}

/* ── Frame/Panel backgrounds ── */
QFrame {
    border: none;
}
QFrame[frameShape="4"], QFrame[frameShape="5"] {
    color: #E2E8F0;
}

